/**
 * Calendar / working time tests.
 */
import { describe, it, expect } from 'vitest';
import { isWorkingDay, getWorkingMinutesInDay, addWorkingMinutes, subtractWorkingMinutes, getWorkingMinutesBetween, DEFAULT_CALENDAR, MINUTES_PER_WORK_DAY, } from '@schedulesync/engine';
import dayjs from 'dayjs';
import utc from 'dayjs/plugin/utc';
dayjs.extend(utc);
describe('isWorkingDay', () => {
    it('Monday is working', () => {
        // 2026-03-02 is Monday
        expect(isWorkingDay(dayjs.utc('2026-03-02'), DEFAULT_CALENDAR)).toBe(true);
    });
    it('Saturday is not working', () => {
        // 2026-03-07 is Saturday
        expect(isWorkingDay(dayjs.utc('2026-03-07'), DEFAULT_CALENDAR)).toBe(false);
    });
    it('Sunday is not working', () => {
        expect(isWorkingDay(dayjs.utc('2026-03-08'), DEFAULT_CALENDAR)).toBe(false);
    });
});
describe('getWorkingMinutesInDay', () => {
    it('standard working day = 480 minutes', () => {
        expect(getWorkingMinutesInDay(dayjs.utc('2026-03-02'), DEFAULT_CALENDAR)).toBe(480);
    });
    it('weekend = 0 minutes', () => {
        expect(getWorkingMinutesInDay(dayjs.utc('2026-03-07'), DEFAULT_CALENDAR)).toBe(0);
    });
});
describe('addWorkingMinutes', () => {
    it('add 1 day (480 min) from Monday 8:00 → Monday 17:00', () => {
        const start = dayjs.utc('2026-03-02T08:00:00');
        const result = addWorkingMinutes(start, 480, DEFAULT_CALENDAR);
        expect(result.format('YYYY-MM-DD')).toBe('2026-03-02');
    });
    it('add 5 days from Monday → Friday', () => {
        const start = dayjs.utc('2026-03-02T08:00:00');
        const result = addWorkingMinutes(start, 480 * 5, DEFAULT_CALENDAR);
        // 5 working days from Mon 8AM ends at Fri 17:00
        expect(result.format('YYYY-MM-DD')).toBe('2026-03-06');
    });
    it('add 0 minutes → same time', () => {
        const start = dayjs.utc('2026-03-02T10:00:00');
        const result = addWorkingMinutes(start, 0, DEFAULT_CALENDAR);
        expect(result.format('YYYY-MM-DDTHH:mm')).toBe('2026-03-02T10:00');
    });
});
describe('subtractWorkingMinutes', () => {
    it('subtract 1 day from Tuesday 17:00 → Tuesday 8:00', () => {
        const d = dayjs.utc('2026-03-03T17:00:00');
        const result = subtractWorkingMinutes(d, 480, DEFAULT_CALENDAR);
        expect(result.format('YYYY-MM-DD')).toBe('2026-03-03');
    });
});
describe('getWorkingMinutesBetween', () => {
    it('Mon 8:00 to Mon 17:00 = 480 min', () => {
        const from = dayjs.utc('2026-03-02T08:00:00');
        const to = dayjs.utc('2026-03-02T17:00:00');
        expect(getWorkingMinutesBetween(from, to, DEFAULT_CALENDAR)).toBe(480);
    });
    it('Mon to next Mon = 2400 min (5 days)', () => {
        const from = dayjs.utc('2026-03-02T08:00:00');
        const to = dayjs.utc('2026-03-09T08:00:00');
        // 5 working days × 480 = 2400
        expect(getWorkingMinutesBetween(from, to, DEFAULT_CALENDAR)).toBe(2400);
    });
    it('same time = 0', () => {
        const d = dayjs.utc('2026-03-02T08:00:00');
        expect(getWorkingMinutesBetween(d, d, DEFAULT_CALENDAR)).toBe(0);
    });
});
describe('MINUTES_PER_WORK_DAY', () => {
    it('equals 480', () => {
        expect(MINUTES_PER_WORK_DAY).toBe(480);
    });
});
